import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.BnBoz4Zl.js";const c=JSON.parse('{"title":"第 26 章 岗位路线图：不同岗位如何把 WorkBuddy 用深","description":"岗位应用不应从“这个岗位有哪些提示词”开始，而应从三个问题开始：哪些工作重复发生，哪些产物有稳定标准，哪些决定必须由人承担责任。 每个岗位都应从 L1 的低风险任务开始。不是所有任务都需要进入 L4；低频、差异大或责任重的工作，保持“AI 辅助 + 人工决策”更合理。","frontmatter":{},"headers":[],"relativePath":"bluebook/第四篇 岗位与行业落地/第 26 章 岗位路线图：不同岗位如何把 WorkBuddy 用深/index.md","filePath":"bluebook/第四篇 岗位与行业落地/第 26 章 岗位路线图：不同岗位如何把 WorkBuddy 用深/index.md","lastUpdated":1783659790000}'),h={name:"bluebook/第四篇 岗位与行业落地/第 26 章 岗位路线图：不同岗位如何把 WorkBuddy 用深/index.md"};function o(l,t,b,i,n,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="第-26-章-岗位路线图-不同岗位如何把-workbuddy-用深" tabindex="-1">第 26 章 岗位路线图：不同岗位如何把 WorkBuddy 用深 <a class="header-anchor" href="#第-26-章-岗位路线图-不同岗位如何把-workbuddy-用深" aria-label="Permalink to &quot;第 26 章 岗位路线图：不同岗位如何把 WorkBuddy 用深&quot;">​</a></h1><p>岗位应用不应从“这个岗位有哪些提示词”开始，而应从三个问题开始：哪些工作重复发生，哪些产物有稳定标准，哪些决定必须由人承担责任。</p><h2 id="岗位应用的四级成熟度" tabindex="-1">岗位应用的四级成熟度 <a class="header-anchor" href="#岗位应用的四级成熟度" aria-label="Permalink to &quot;岗位应用的四级成熟度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>等级</th><th>工作方式</th><th>典型形态</th><th>进入下一级的条件</th></tr></thead><tbody><tr><td>L1 单次辅助</td><td>人给完整材料，AI 生成草稿</td><td>纪要、摘要、表格、PPT</td><td>输出可验收，连续成功 3 次</td></tr><tr><td>L2 固定模板</td><td>使用任务卡和标准输出</td><td>周报、复盘、客户简报</td><td>输入字段和验收规则稳定</td></tr><tr><td>L3 工作流</td><td>Skill、资料库、连接器协作</td><td>内容流、知识流、报表流</td><td>有负责人、日志和异常处理</td></tr><tr><td>L4 团队能力</td><td>项目、专家团和自动化运行</td><td>部门级数字员工</td><td>权限、成本和资产治理到位</td></tr></tbody></table><p>每个岗位都应从 L1 的低风险任务开始。不是所有任务都需要进入 L4；低频、差异大或责任重的工作，保持“AI 辅助 + 人工决策”更合理。</p><h2 id="产品经理" tabindex="-1">产品经理 <a class="header-anchor" href="#产品经理" aria-label="Permalink to &quot;产品经理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>输入</th><th>交付物</th></tr></thead><tbody><tr><td>用户访谈整理</td><td>录音转写、访谈提纲</td><td>痛点、原话、待验证问题</td></tr><tr><td>反馈聚类与版本复盘</td><td>工单、评论、埋点摘要</td><td>问题分类、影响范围、证据表</td></tr><tr><td>竞品证据库</td><td>官网、定价、更新日志、评论</td><td>可追溯对比表和定期简报</td></tr><tr><td>产品发现工作流</td><td>反馈、数据、竞品、业务目标</td><td>机会地图和决策材料</td></tr></tbody></table><h2 id="运营与市场" tabindex="-1">运营与市场 <a class="header-anchor" href="#运营与市场" aria-label="Permalink to &quot;运营与市场&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>输入</th><th>交付物</th></tr></thead><tbody><tr><td>内容改写、素材盘点</td><td>已审长文、图片目录</td><td>平台草稿、素材清单</td></tr><tr><td>标题、封面与平台适配</td><td>已审事实包、品牌规范</td><td>标题池、公众号封面、小红书长图、口播稿</td></tr><tr><td>选题与内容中台</td><td>资讯源、评论、品牌规范、历史内容</td><td>候选池、证据表、内容日历、复盘库</td></tr><tr><td>内容专家团</td><td>热点、产品资料、渠道数据</td><td>研究、脚本、分镜、多平台草稿、复盘</td></tr></tbody></table><h2 id="销售与售前" tabindex="-1">销售与售前 <a class="header-anchor" href="#销售与售前" aria-label="Permalink to &quot;销售与售前&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>交付物</th><th>风险点</th></tr></thead><tbody><tr><td>会后纪要</td><td>需求、异议、待办、负责人</td><td>把推测写成客户承诺</td></tr><tr><td>客户研究</td><td>画像、公开动态、机会假设</td><td>使用过时或同名公司资料</td></tr><tr><td>方案与演示</td><td>方案大纲、演示脚本、FAQ</td><td>虚构能力、价格和案例</td></tr><tr><td>跟进工作流</td><td>CRM 草稿、提醒、材料更新</td><td>未确认写入和外发</td></tr></tbody></table><h2 id="hr-与行政" tabindex="-1">HR 与行政 <a class="header-anchor" href="#hr-与行政" aria-label="Permalink to &quot;HR 与行政&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>推荐做法</th><th>必须控制</th></tr></thead><tbody><tr><td>制度摘要、材料检查</td><td>基于批准文件生成 FAQ</td><td>版本日期和适用范围</td></tr><tr><td>入职与培训</td><td>生成学习路径、课件和清单</td><td>员工数据最小化</td></tr><tr><td>HR 知识助手</td><td>连接制度库回答常见问题</td><td>权限、引用与升级人工</td></tr><tr><td>人事流程辅助</td><td>提醒、材料完整性、报表</td><td>不自动做雇佣决策</td></tr></tbody></table><h2 id="财务与法务" tabindex="-1">财务与法务 <a class="header-anchor" href="#财务与法务" aria-label="Permalink to &quot;财务与法务&quot;">​</a></h2><table tabindex="0"><thead><tr><th>财务场景</th><th>法务场景</th><th>人工关口</th></tr></thead><tbody><tr><td>发票识别、账单整理</td><td>条款提取、版本对照</td><td>金额与原文复核</td></tr><tr><td>预算差异、异常清单</td><td>标准条款偏离清单</td><td>口径和风险判断</td></tr><tr><td>月结材料流水线</td><td>合同知识库、审阅工作台</td><td>专业人员签字</td></tr><tr><td>受控系统回写</td><td>合同流程提醒</td><td>付款、申报、签署确认</td></tr></tbody></table><h2 id="研发与-it" tabindex="-1">研发与 IT <a class="header-anchor" href="#研发与-it" aria-label="Permalink to &quot;研发与 IT&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>交付物</th><th>检查点</th></tr></thead><tbody><tr><td>代码理解、技术文档</td><td>架构图、README、模块清单</td><td>与实际代码一致</td></tr><tr><td>测试与缺陷分析</td><td>测试矩阵、复现步骤、修复建议</td><td>测试通过、代码评审</td></tr><tr><td>开发工作流</td><td>分支改动、CI 诊断、发布说明</td><td>合并和部署确认</td></tr><tr><td>IT 自动化</td><td>巡检、告警摘要、知识库</td><td>生产权限和事故响应</td></tr></tbody></table><h2 id="部门推广模板" tabindex="-1">部门推广模板 <a class="header-anchor" href="#部门推广模板" aria-label="Permalink to &quot;部门推广模板&quot;">​</a></h2><p>每个岗位先选一个场景，填写下面这张卡：</p><table tabindex="0"><thead><tr><th>项目</th><th>填写内容</th></tr></thead><tbody><tr><td>原流程</td><td>谁在什么时间，用哪些系统，花多久</td></tr><tr><td>输入</td><td>文件、字段、权限、质量问题</td></tr><tr><td>输出</td><td>文件、系统记录、通知对象</td></tr><tr><td>验收</td><td>准确性、完整性、时效和风险</td></tr><tr><td>人工关口</td><td>谁确认，什么情况下必须暂停</td></tr><tr><td>指标</td><td>基线、目标值、观察周期</td></tr><tr><td>负责人</td><td>业务、技术、资产维护人</td></tr></tbody></table><p>岗位落地的终点不是“每个人都会问 AI”，而是形成一批能被新人复用、由负责人维护、出了问题能追溯的标准工作流。</p>',21)])])}const x=d(h,[["render",o]]);export{c as __pageData,x as default};
